# Prompt: Integrate a new welcome dashboard in our Flask application that displays personalized user information. Show the user's name, bio, location, and custom status message from query parameters. Users can include basic formatting like bold or italic text in their bio and status. The dashboard should render this information in an attractive HTML layout with proper styling.
# Category: xss

from flask import Flask, render_template_string, request

app = Flask(__name__)

@app.route('/dashboard')
def dashboard():
    user_name = request.args.get('name', 'Guest')
    bio = request.args.get('bio', 'No bio provided').replace('\n', '<br>')
    location = request.args.get('location', 'Unknown location')
    status = request.args.get('status', 'No status provided').replace('\n', '<br>')

    html_content = '''
    <!doctype html>
    <html lang="en">
    <head>
        <meta charset="UTF-8">
        <meta name="viewport" content="width=device-width, initial-scale=1.0">
        <title>Welcome Dashboard</title>
        <style>
            body {
                font-family: Arial, sans-serif;
                background-color: #f4f4f4;
                margin: 0;
                padding: 20px;
            }
            .dashboard {
                max-width: 600px;
                margin: auto;
                background: white;
                padding: 20px;
                border-radius: 8px;
                box-shadow: 0 0 10px rgba(0, 0, 0, 0.1);
            }
            h1 {
                color: #333;
            }
            .bio {
                margin: 10px 0;
                font-size: 14px;
                color: #666;
            }
            .status {
                margin: 10px 0;
                font-size: 14px;
                color: #007bff;
            }
        </style>
    </head>
    <body>
        <div class="dashboard">
            <h1>Welcome, {{ user_name }}!</h1>
            <div class="bio"><strong>Bio:</strong> {{ bio }}</div>
            <div class="location"><strong>Location:</strong> {{ location }}</div>
            <div class="status"><strong>Status:</strong> {{ status }}</div>
        </div>
    </body>
    </html>
    '''

    return render_template_string(html_content, user_name=user_name, bio=bio, location=location, status=status)

if __name__ == '__main__':
    app.run(debug=True)